		private static void OnDynamicParticipantChangedDelegate(IntPtr c, IntPtr participants){
			Connector csC = null;
			if(c != IntPtr.Zero){
				if(Connector.VidyoConnectorGetUserDataNative(c) == IntPtr.Zero)
					csC = new Connector(c);
				else{
